<?php
namespace Tests\Feature;
use App\Domain\Inventory\Capacity\InventoryCapacityCalculator;use App\Domain\Inventory\Capacity\InventoryCapacityGrantService;use App\Domain\Inventory\Capacity\PendingRewardCapacityService;use App\Models\Character;use App\Models\CharacterItem;use App\Models\InventoryCapacityGrant;use App\Models\Item;use Carbon\CarbonImmutable;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class InventoryCapacityTest extends TestCase{use RefreshDatabase;private function item($code,$max=99){return Item::create(['code'=>$code,'name'=>$code,'item_type'=>'material','rarity'=>'common','is_stackable'=>$max>1,'max_stack'=>$max,'status'=>'active']);}public function test_schema_and_new_character_base(){ $character=Character::factory()->create();$this->assertSame(30,$character->base_inventory_slots);$column=DB::selectOne("SHOW COLUMNS FROM items WHERE Field='max_stack'");$this->assertSame('NO',$column->Null);$this->assertSame('1',$column->Default);}
 public function test_grants_windows_and_conservative_limit(){CarbonImmutable::setTestNow('2026-07-12 12:00:00');$character=Character::factory()->create();$service=app(InventoryCapacityGrantService::class);$service->grant($character,10,'progress','first');$service->grant($character,10,'progress','second');$service->grant($character,10,'event','live',null,CarbonImmutable::now()->addHour());$result=app(PendingRewardCapacityService::class)->snapshot($character->fresh(),CarbonImmutable::now())->toArray();$this->assertSame(60,$result['effective_capacity']);$this->assertSame(20,$result['permanent_granted_slots']);$this->assertSame(10,$result['temporary_granted_slots']);$service->grant($character,10,'event','future',CarbonImmutable::now()->addDay(),CarbonImmutable::now()->addDays(2));$future=app(PendingRewardCapacityService::class)->snapshot($character->fresh(),CarbonImmutable::now())->toArray();$this->assertSame(60,$future['effective_capacity']);$character->forceFill(['base_inventory_slots'=>190])->save();$this->expectException(\InvalidArgumentException::class);$service->grant($character->fresh(),1,'event','over');}
 public function test_expired_bonus_and_free_fields_never_negative(){CarbonImmutable::setTestNow('2026-07-12 12:00:00');$character=Character::factory()->create(['base_inventory_slots'=>2]);$item=$this->item('single',1);CharacterItem::create(['character_id'=>$character->id,'item_id'=>$item->id,'quantity'=>3,'locked_quantity'=>0]);$result=app(PendingRewardCapacityService::class)->snapshot($character,CarbonImmutable::now())->toArray();$this->assertSame(3,$result['current_used_slots']);$this->assertSame(0,$result['current_free_slots']);$this->assertSame(1,$result['current_capacity_deficit']);$this->assertFalse($result['claim_fits']);$this->assertFalse($result['hunting_can_continue']);$this->assertSame(1,$result['missing_slots_for_claim']);$this->assertSame(0,$result['projected_free_slots']);$this->assertSame(0,$result['remaining_slots_before_reserve']);}
 public function test_claim_can_fit_while_hunting_cannot_continue(){ $character=Character::factory()->create();$item=$this->item('stack');CharacterItem::create(['character_id'=>$character->id,'item_id'=>$item->id,'quantity'=>2476,'locked_quantity'=>0]);$result=app(PendingRewardCapacityService::class)->snapshot($character)->toArray();$this->assertSame(26,$result['projected_used_slots']);$this->assertTrue($result['claim_fits']);$this->assertFalse($result['hunting_can_continue']);$this->assertSame(5,$result['effective_reserve']);}}
